    private boolean execRecord(int nodeId, User user, RagicBundle bundle) {
        APIQuery query = new APIQuery(AP_NAME, "/custom", 36);
        query.setIfEidNaming(true);
        query.setBundle(bundle);
        APIEntry entry = query.getAPIEntry(nodeId);
        if (entry.getFieldValue(1000529).equals("Y")) {
            return false;
        }
        entry.setFieldValue(1000529, "Y");
        entry.save(user, bundle);
        return true;
    }

    private void setRecord(APIEntry entry, int[] fields) {

        List<String> records = new LinkedList<>();

        for (int i = 1; i < fields.length; i++) {
            for (int j = 1; j < fields.length; j++) {
                records.addAll(queryTheSameFieldValue(entry, fields[i], fields[j]));
            }
        }

        boolean isFirst = true;
        StringBuilder allRecords = new StringBuilder();
        for(String record : records) {
            if (isFirst) {
                allRecords.append(record);
                isFirst = false;
            } else {
                allRecords.append("\n").append(record);
            }
        }
        entry.setFieldValue(fields[0], isFirst ? NO_RECORD_STRING : allRecords.toString());
    }

    private List<String> queryTheSameFieldValue(APIEntry entry, int domainId, int anotherDomainId) {

        String caseNumber = entry.getFieldValue(CASE_NUMBER);

        List<String> records = new LinkedList<>();

        boolean isContact = anotherDomainId == CONTACT_HOME_PHONE || anotherDomainId == CONTACT_MOBILE_PHONE;

        String regex = getRegex(entry, domainId, domainId == CONTACT_HOME_PHONE || domainId == CONTACT_MOBILE_PHONE);

        if (regex.length() < 1) {
            return records;
        }

        APIQuery query = new APIQuery(AP_NAME, ALL_SHEET_PATH, isContact ? CONTACT_SHEET_INDEX : ALL_SHEET_INDEX);
        query.setIfEidNaming(true);
        query.setFiltersStringV2(new String[]{anotherDomainId + "|" + NUIFilter.OPERAND_REGEX + "|" + regex});

        Iterator<APIEntry> it = query.getAPIResults().iterator(query.getForm());

        int rootNodeId = -1;
        int lastNodeId = -1;

        while(it.hasNext()) {
            APIEntry e = it.next();
            if(isContact) {
                String contactCaseNumber = e.getFieldValue(CONTACT_CASE_NUMBER);
                if (!caseNumber.equals(contactCaseNumber)) {
                    APIQuery q = new APIQuery(AP_NAME, ALL_SHEET_PATH, ALL_SHEET_INDEX);
                    q.setIfEidNaming(true);
                    q.setFiltersStringV2(new String[]{CASE_NUMBER + "|" + NUIFilter.OPERAND_EQ + "|" + contactCaseNumber});
                    rootNodeId = q.getAPIResults().iterator(q.getForm()).next().getRootNodeId();
                }
            } else if (!caseNumber.equals(e.getFieldValue(CASE_NUMBER))) {
                rootNodeId = e.getRootNodeId();
            }
            if (rootNodeId != lastNodeId) {
                records.add(fieldName.get(domainId) + " 出現於 " + allSheetUrl + rootNodeId + " 之 " + fieldName.get(anotherDomainId));
                lastNodeId = rootNodeId;
            }
        }

        return records;
    }

    private String getRegex(APIEntry entry, int domainId, boolean contact) {
        StringBuilder regex = new StringBuilder();
        if (contact) {
            int contactCount = entry.getSubtableSize(CONTACT_SUBTABLE);
            boolean isFirst = true;
            for (int i = 0; i < contactCount; i++) {
                String phone = entry.getSubtableFieldValue(CONTACT_SUBTABLE, i, domainId + "");
                if (phone.length() > 0) {
                    if (isFirst) {
                        isFirst = false;
                    } else {
                        regex.append("&#124;");
                    }
                    regex.append(phone);
                }
            }
        } else {
            String fieldValue = entry.getFieldValue(domainId);
            if (fieldValue.length() == 0) {
                return "";
            }
            String areaCode = "";
            if (domainId == COMPANY_PHONE) {
                areaCode = entry.getFieldValue(1000250);             // 公司電話區號
            } else if (domainId == GUARANTOR_PHONE) {
                areaCode = entry.getFieldValue(1000260);             // 保人聯絡電話區號
            }
            regex.append(fieldValue);
            if (areaCode.length() > 0) {
                regex.append("&#124;").append(areaCode).append(fieldValue);
            }
        }
        return regex.toString();
    }


